import React, { useState, useMemo } from 'react';
import { useSelector } from 'react-redux';
import toast from 'react-hot-toast';

// ── helpers ───────────────────────────────────────────────
function downloadCSV(filename, headers, rows) {
  const lines = [headers, ...rows].map(r => r.map(v => `"${String(v).replace(/"/g,'""')}"`).join(','));
  const blob  = new Blob(['\uFEFF' + lines.join('\r\n')], { type: 'text/csv;charset=utf-8;' });
  const url   = URL.createObjectURL(blob);
  const a     = document.createElement('a');
  a.href = url; a.download = filename; a.click();
  URL.revokeObjectURL(url);
}

const S = {                                               // status config
  present: { short:'P',  label:'Present', bg:'#D1FAE5', c:'#065F46',  bar:'#10B981' },
  absent:  { short:'A',  label:'Absent',  bg:'#FEE2E2', c:'#991B1B',  bar:'#EF4444' },
  leave:   { short:'L',  label:'Leave',   bg:'#FEF3C7', c:'#92400E',  bar:'#F59E0B' },
  late:    { short:'Lt', label:'Late',    bg:'#EDE9FE', c:'#5B21B6',  bar:'#7C3AED' },
};

const cell  = { padding:'10px 14px', borderBottom:'0.5px solid #F3F4F6' };
const thead = { padding:'10px 14px', textAlign:'left', background:'#F9FAFB', color:'#6B7280', fontSize:10, fontWeight:700, textTransform:'uppercase', letterSpacing:'.06em', borderBottom:'1px solid #E5E7EB', whiteSpace:'nowrap' };
const inp   = { padding:'9px 12px', border:'1.5px solid #E5E7EB', borderRadius:9, fontSize:13, outline:'none', background:'#fff', fontFamily:'inherit' };

const TABS = ['Date-wise Student Report', 'Class Summary Report', 'Monthly Overview'];

export default function AttendanceReport() {
  const students   = useSelector(s => s.admission.students);
  const classes    = useSelector(s => s.admission.classes);
  const attendance = useSelector(s => s.attendance?.records || {});  // fallback empty

  const today    = new Date().toISOString().split('T')[0];
  const [tab,    setTab]    = useState(0);
  const [cls,    setCls]    = useState('');
  const [sec,    setSec]    = useState('');
  const [date,   setDate]   = useState(today);
  const [fromDt, setFromDt] = useState(() => { const d=new Date(); d.setDate(1); return d.toISOString().split('T')[0]; });
  const [toDt,   setToDt]   = useState(today);

  // ── sections for selected class ───────────────────────────
  const sections = useMemo(() =>
    [...new Set(students.filter(s=>!cls||s.cls===cls).map(s=>s.sec))].filter(Boolean).sort()
  ,[students,cls]);

  // ── all dates that have attendance ───────────────────────
  const allSavedDates = useMemo(() => {
    const s = new Set(Object.keys(attendance).map(k=>k.split('|')[0]).filter(Boolean));
    if (!s.size) s.add(today);
    return [...s].sort();
  },[attendance]);

  // ── filtered + sorted students ───────────────────────────
  const filteredStudents = useMemo(() =>
    [...students]
      .filter(s=>(!cls||s.cls===cls)&&(!sec||s.sec===sec))
      .sort((a,b)=>a.name.localeCompare(b.name))
  ,[students,cls,sec]);

  // ── dates in range ────────────────────────────────────────
  const rangeDates = useMemo(() =>
    allSavedDates.filter(d=>d>=fromDt&&d<=toDt)
  ,[allSavedDates,fromDt,toDt]);

  // ── get status for a student+date ────────────────────────
  const getStatus = (studentId, d) => attendance[`${d}|${studentId}`] || null;

  // ── per-student stats across range ───────────────────────
  const studentStats = useMemo(() =>
    filteredStudents.map(st => {
      const byDate = {};
      rangeDates.forEach(d => { byDate[d] = getStatus(st.id, d); });
      const marked  = rangeDates.filter(d=>byDate[d]);
      const present = marked.filter(d=>byDate[d]==='present'||byDate[d]==='late').length;
      const pct     = marked.length ? Math.round((present/marked.length)*100) : null;
      return { ...st, byDate, present, absent: marked.filter(d=>byDate[d]==='absent').length, leave: marked.filter(d=>byDate[d]==='leave').length, late: marked.filter(d=>byDate[d]==='late').length, marked: marked.length, pct };
    })
  ,[filteredStudents,rangeDates,attendance]);

  // ── class summary for single date ────────────────────────
  const classSummary = useMemo(() =>
    classes.map(cl => {
      const sts = students.filter(s=>s.cls===cl);
      const counts = { present:0, absent:0, leave:0, late:0, unmarked:0 };
      sts.forEach(s => {
        const v = getStatus(s.id, date);
        if (v && counts[v]!==undefined) counts[v]++; else counts.unmarked++;
      });
      const total = sts.length;
      const pct   = total>0 ? Math.round(((counts.present+counts.late)/total)*100) : 0;
      return { cls:cl, total, ...counts, pct };
    }).filter(c=>c.total>0)
  ,[classes,students,date,attendance]);

  // ── monthly overview (all dates, all classes) ─────────────
  const monthDates = useMemo(() => {
    const [y,m] = fromDt.split('-');
    const days = new Date(parseInt(y), parseInt(m), 0).getDate();
    return Array.from({length:days},(_,i)=>`${y}-${m}-${String(i+1).padStart(2,'0')}`);
  },[fromDt]);

  const monthlyData = useMemo(() => {
    return monthDates.map(d => {
      const allSts  = students;
      const marked  = allSts.filter(s => getStatus(s.id,d));
      const present = allSts.filter(s => ['present','late'].includes(getStatus(s.id,d))).length;
      const absent  = allSts.filter(s => getStatus(s.id,d)==='absent').length;
      const pct     = marked.length>0 ? Math.round((present/marked.length)*100) : null;
      return { date:d, total:allSts.length, marked:marked.length, present, absent, pct };
    });
  },[monthDates,students,attendance]);

  // ── DOWNLOAD ──────────────────────────────────────────────
  const dlDatewise = () => {
    const headers = ['S.No','Adm No','Student Name','Class','Section',...rangeDates,'Days Present','Days Absent','Days Leave','Days Late','Total Marked','Attendance %'];
    const rows    = studentStats.map((s,i)=>[
      i+1, s.adm, s.name, s.cls, s.sec,
      ...rangeDates.map(d=>s.byDate[d]?S[s.byDate[d]]?.short||'—':'—'),
      s.present, s.absent, s.leave, s.late, s.marked,
      s.pct!==null?`${s.pct}%`:'N/A'
    ]);
    downloadCSV(`Datewise_Attendance_${cls||'All'}_${fromDt}_to_${toDt}.csv`, headers, rows);
    toast.success('📥 Date-wise attendance downloaded!');
  };

  const dlClassSummary = () => {
    const headers = ['Class','Total Students','Present','Absent','Leave','Late','Not Marked','Attendance %'];
    const rows    = classSummary.map(c=>[c.cls,c.total,c.present,c.absent,c.leave,c.late,c.unmarked,`${c.pct}%`]);
    rows.push(['TOTAL',
      classSummary.reduce((a,c)=>a+c.total,0),
      classSummary.reduce((a,c)=>a+c.present,0),
      classSummary.reduce((a,c)=>a+c.absent,0),
      classSummary.reduce((a,c)=>a+c.leave,0),
      classSummary.reduce((a,c)=>a+c.late,0),
      classSummary.reduce((a,c)=>a+c.unmarked,0),
      `${classSummary.length>0?Math.round((classSummary.reduce((a,c)=>a+c.present,0)/classSummary.reduce((a,c)=>a+c.total,0))*100):0}%`
    ]);
    downloadCSV(`Class_Summary_${date}.csv`, headers, rows);
    toast.success('📥 Class summary downloaded!');
  };

  const dlMonthly = () => {
    const headers = ['Date','Day','Total Students','Marked','Present','Absent','Attendance %'];
    const rows    = monthlyData.map(r=>[
      r.date,
      new Date(r.date).toLocaleDateString('en-IN',{weekday:'short'}),
      r.total, r.marked, r.present, r.absent,
      r.pct!==null?`${r.pct}%`:'Not marked'
    ]);
    downloadCSV(`Monthly_Overview_${fromDt.substring(0,7)}.csv`, headers, rows);
    toast.success('📥 Monthly overview downloaded!');
  };

  // ── pill badge ────────────────────────────────────────────
  const Pct = ({v}) => {
    if (v===null) return <span style={{color:'#D1D5DB',fontSize:11}}>—</span>;
    const [bg,c] = v>=75?['#D1FAE5','#065F46']:v>=50?['#FEF3C7','#92400E']:['#FEE2E2','#991B1B'];
    return <span style={{padding:'3px 10px',borderRadius:20,fontSize:11,fontWeight:700,background:bg,color:c}}>{v}%</span>;
  };

  const Bar = ({pct,h=8}) => {
    const color = pct>=75?'#10B981':pct>=50?'#F59E0B':'#EF4444';
    return (
      <div style={{height:h,background:'#F3F4F6',borderRadius:4,overflow:'hidden',minWidth:80}}>
        <div style={{height:'100%',width:`${pct}%`,background:color,borderRadius:4,transition:'width .6s'}}/>
      </div>
    );
  };

  return (
    <div>
      {/* Page header */}
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:18,flexWrap:'wrap',gap:12}}>
        <div>
          <h2 style={{fontSize:20,fontWeight:700,color:'#111827'}}>Attendance Report</h2>
          <p style={{fontSize:12,color:'#6B7280',marginTop:2}}>Date-wise · Class summary · Monthly overview · Download CSV</p>
        </div>
      </div>

      {/* Tabs */}
      <div style={{display:'flex',gap:2,borderBottom:'1.5px solid #E5E7EB',marginBottom:20}}>
        {TABS.map((t,i)=>(
          <button key={t} onClick={()=>setTab(i)}
            style={{padding:'10px 18px',border:'none',borderRadius:'8px 8px 0 0',background:tab===i?'#1E1B4B':'transparent',color:tab===i?'#fff':'#6B7280',fontSize:13,fontWeight:tab===i?700:500,cursor:'pointer',borderBottom:`2px solid ${tab===i?'#1E1B4B':'transparent'}`,marginBottom:-1.5,transition:'all .15s'}}>
            {t}
          </button>
        ))}
      </div>

      {/* ══ TAB 0: DATE-WISE STUDENT REPORT ══ */}
      {tab===0 && (
        <>
          {/* Filters */}
          <div style={{display:'flex',gap:12,marginBottom:16,flexWrap:'wrap',alignItems:'flex-end',padding:'14px 16px',background:'#fff',borderRadius:12,border:'0.5px solid #E5E7EB'}}>
            <div style={{display:'flex',flexDirection:'column',gap:5}}>
              <label style={{fontSize:11,fontWeight:700,color:'#6B7280',textTransform:'uppercase',letterSpacing:'.06em'}}>From Date</label>
              <input type="date" value={fromDt} onChange={e=>setFromDt(e.target.value)} style={inp}/>
            </div>
            <div style={{display:'flex',flexDirection:'column',gap:5}}>
              <label style={{fontSize:11,fontWeight:700,color:'#6B7280',textTransform:'uppercase',letterSpacing:'.06em'}}>To Date</label>
              <input type="date" value={toDt} onChange={e=>setToDt(e.target.value)} min={fromDt} style={inp}/>
            </div>
            <div style={{display:'flex',flexDirection:'column',gap:5}}>
              <label style={{fontSize:11,fontWeight:700,color:'#6B7280',textTransform:'uppercase',letterSpacing:'.06em'}}>Class</label>
              <select value={cls} onChange={e=>{setCls(e.target.value);setSec('');}} style={{...inp,minWidth:140}}>
                <option value=''>All Classes</option>
                {classes.map(c=><option key={c}>{c}</option>)}
              </select>
            </div>
            <div style={{display:'flex',flexDirection:'column',gap:5}}>
              <label style={{fontSize:11,fontWeight:700,color:'#6B7280',textTransform:'uppercase',letterSpacing:'.06em'}}>Section</label>
              <select value={sec} onChange={e=>setSec(e.target.value)} style={{...inp,minWidth:110}} disabled={!sections.length}>
                <option value=''>All</option>
