            </div>
            <div style={{alignSelf:'flex-end',display:'flex',gap:10}}>
              <div style={{padding:'9px 14px',background:'#EDE9F8',borderRadius:9,fontSize:12,fontWeight:700,color:'#1E1B4B'}}>
