            <span style={{display:'flex',alignItems:'center',gap:5,padding:'4px 12px',borderRadius:20,background:'#F3F4F6',fontSize:11,fontWeight:600,color:'#6B7280'}}>
              🟢 ≥75% &nbsp;🟡 ≥50% &nbsp;🔴 &lt;50%
            </span>
          </div>

          {/* Table */}
          <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden'}}>
            {studentStats.length===0 ? (
              <div style={{padding:48,textAlign:'center',color:'#9CA3AF'}}>
                <div style={{fontSize:40,marginBottom:10}}>📅</div>
                <div style={{fontWeight:600,color:'#6B7280',fontSize:14}}>No data found</div>
                <div style={{fontSize:12,marginTop:4}}>Mark attendance first in the Attendance module</div>
              </div>
            ) : (
              <div style={{overflowX:'auto'}}>
                <table style={{width:'100%',borderCollapse:'collapse',fontSize:12}}>
                  <thead>
                    <tr>
                      <th style={{...thead,position:'sticky',left:0,zIndex:2}}>#</th>
                      <th style={{...thead,position:'sticky',left:36,zIndex:2,minWidth:180}}>Student</th>
                      <th style={{...thead}}>Class</th>
                      {rangeDates.map(d=>(
                        <th key={d} style={{...thead,textAlign:'center',minWidth:56,fontSize:9}}>
                          {new Date(d+'T00:00:00').toLocaleDateString('en-IN',{day:'2-digit',month:'short'})}
