                      ))}
                      <th style={{...thead,textAlign:'center'}}>Present</th>
                      <th style={{...thead,textAlign:'center'}}>Absent</th>
                      <th style={{...thead,textAlign:'center'}}>Leave</th>
                      <th style={{...thead,textAlign:'center'}}>Marked</th>
                      <th style={{...thead,textAlign:'center',minWidth:90}}>Attend %</th>
                    </tr>
                  </thead>
                  <tbody>
                    {studentStats.map((s,i)=>(
                      <tr key={s.id}
                        onMouseEnter={e=>e.currentTarget.style.background='#F5F3FF'}
                        onMouseLeave={e=>e.currentTarget.style.background=''}>
                        <td style={{...cell,position:'sticky',left:0,background:'inherit',color:'#9CA3AF',fontSize:11}}>{i+1}</td>
                        <td style={{...cell,position:'sticky',left:36,background:'inherit'}}>
                          <div style={{display:'flex',alignItems:'center',gap:8}}>
                            <div style={{width:28,height:28,borderRadius:7,background:'#EDE9F8',display:'flex',alignItems:'center',justifyContent:'center',fontSize:11,fontWeight:700,color:'#1E1B4B',flexShrink:0}}>{s.name[0]}</div>
                            <div>
                              <div style={{fontWeight:600,color:'#111827'}}>{s.name}</div>
                              <div style={{fontSize:10,color:'#9CA3AF'}}>{s.adm}</div>
                            </div>
                          </div>
                        </td>
                        <td style={{...cell,color:'#6B7280'}}>{s.cls}-{s.sec}</td>
                        {rangeDates.map(d=>{
                          const v=s.byDate[d];
                          const cfg=v?S[v]:null;
                          return (
                            <td key={d} style={{...cell,textAlign:'center'}}>
                              {cfg
                                ? <span style={{display:'inline-block',padding:'2px 6px',borderRadius:6,fontSize:10,fontWeight:700,background:cfg.bg,color:cfg.c}}>{cfg.short}</span>
                                : <span style={{color:'#E5E7EB',fontSize:12}}>—</span>}
                            </td>
                          );
                        })}
                        <td style={{...cell,textAlign:'center',fontWeight:700,color:'#065F46'}}>{s.present}</td>
                        <td style={{...cell,textAlign:'center',fontWeight:700,color:'#991B1B'}}>{s.absent}</td>
                        <td style={{...cell,textAlign:'center',fontWeight:700,color:'#92400E'}}>{s.leave}</td>
                        <td style={{...cell,textAlign:'center',color:'#6B7280'}}>{s.marked}</td>
                        <td style={{...cell,textAlign:'center'}}><Pct v={s.pct}/></td>
                      </tr>
                    ))}
                  </tbody>
                  {/* Summary footer */}
                  <tfoot>
                    <tr style={{background:'#F9FAFB',borderTop:'2px solid #E5E7EB'}}>
                      <td colSpan={3} style={{...cell,fontWeight:800,color:'#111827'}}>TOTAL ({studentStats.length} students)</td>
                      {rangeDates.map(d=>{
                        const dayPresent = filteredStudents.filter(s=>['present','late'].includes(getStatus(s.id,d))).length;
                        const dayTotal   = filteredStudents.filter(s=>getStatus(s.id,d)).length;
                        const dayPct     = dayTotal>0?Math.round((dayPresent/dayTotal)*100):null;
                        return (
                          <td key={d} style={{...cell,textAlign:'center'}}>
                            {dayPct!==null
                              ? <span style={{fontSize:10,fontWeight:700,color:dayPct>=75?'#065F46':dayPct>=50?'#92400E':'#991B1B'}}>{dayPct}%</span>
                              : <span style={{color:'#E5E7EB'}}>—</span>}
                          </td>
                        );
                      })}
                      <td style={{...cell,textAlign:'center',fontWeight:800,color:'#065F46'}}>{studentStats.reduce((a,s)=>a+s.present,0)}</td>
                      <td style={{...cell,textAlign:'center',fontWeight:800,color:'#991B1B'}}>{studentStats.reduce((a,s)=>a+s.absent,0)}</td>
                      <td style={{...cell,textAlign:'center',fontWeight:800,color:'#92400E'}}>{studentStats.reduce((a,s)=>a+s.leave,0)}</td>
                      <td style={{...cell,textAlign:'center',color:'#6B7280',fontWeight:700}}>{studentStats.reduce((a,s)=>a+s.marked,0)}</td>
                      <td style={{...cell,textAlign:'center'}}>
                        <Pct v={studentStats.length>0?Math.round((studentStats.reduce((a,s)=>a+s.present,0)/Math.max(1,studentStats.reduce((a,s)=>a+s.marked,0)))*100):null}/>
                      </td>
                    </tr>
                  </tfoot>
                </table>
              </div>
            )}
          </div>
        </>
      )}

      {/* ══ TAB 1: CLASS SUMMARY ══ */}
      {tab===1 && (
        <>
          <div style={{display:'flex',gap:12,marginBottom:16,flexWrap:'wrap',alignItems:'flex-end',padding:'14px 16px',background:'#fff',borderRadius:12,border:'0.5px solid #E5E7EB'}}>
            <div style={{display:'flex',flexDirection:'column',gap:5}}>
              <label style={{fontSize:11,fontWeight:700,color:'#6B7280',textTransform:'uppercase',letterSpacing:'.06em'}}>Date</label>
              <input type="date" value={date} onChange={e=>setDate(e.target.value)} style={inp}/>
            </div>
            <button onClick={dlClassSummary}
              style={{padding:'9px 18px',background:'#1E40AF',color:'#fff',border:'none',borderRadius:9,fontSize:12,fontWeight:700,cursor:'pointer',alignSelf:'flex-end',display:'flex',alignItems:'center',gap:7}}>
              📥 Download CSV
            </button>
          </div>

          {/* Top stats */}
          <div style={{display:'grid',gridTemplateColumns:'repeat(5,1fr)',gap:12,marginBottom:18}}>
            {[
              ['Total Students',  students.length,                                                          '#EDE9F8','#1E1B4B'],
              ['Present',         classSummary.reduce((a,c)=>a+c.present,0),                               '#D1FAE5','#065F46'],
              ['Absent',          classSummary.reduce((a,c)=>a+c.absent,0),                                '#FEE2E2','#991B1B'],
              ['On Leave',        classSummary.reduce((a,c)=>a+c.leave,0),                                 '#FEF3C7','#92400E'],
              ['School Avg',      students.length>0?`${Math.round((classSummary.reduce((a,c)=>a+c.present,0)/students.length)*100)}%`:'—', '#DBEAFE','#1E40AF'],
            ].map(([l,v,bg,c])=>(
              <div key={l} style={{padding:'16px',background:bg,borderRadius:12,textAlign:'center'}}>
                <div style={{fontSize:26,fontWeight:800,color:c,lineHeight:1}}>{v}</div>
                <div style={{fontSize:11,color:c,marginTop:5,fontWeight:600,opacity:.85}}>{l}</div>
              </div>
            ))}
          </div>

          <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden'}}>
            <div style={{padding:'12px 16px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
              <span style={{fontWeight:700,fontSize:13}}>📊 Class-wise Attendance — {date}</span>
              <span style={{fontSize:11,color:'#9CA3AF'}}>{classSummary.length} active classes</span>
            </div>
            <table style={{width:'100%',borderCollapse:'collapse',fontSize:12}}>
              <thead><tr>
                {['Class','Total Students','Present','Absent','Leave','Late','Not Marked','Attendance %','Progress Bar'].map(h=>(
                  <th key={h} style={thead}>{h}</th>
                ))}
              </tr></thead>
              <tbody>
                {classSummary.length===0&&(
                  <tr><td colSpan={9} style={{padding:40,textAlign:'center',color:'#9CA3AF'}}>
                    <div style={{fontSize:36,marginBottom:8}}>🏫</div>
                    <div style={{fontWeight:600,color:'#6B7280'}}>No class data</div>
                    <div style={{fontSize:12,marginTop:4}}>Add students to classes first</div>
