                {classSummary.map(c=>(
                  <tr key={c.cls}
                    onMouseEnter={e=>e.currentTarget.style.background='#F5F3FF'}
                    onMouseLeave={e=>e.currentTarget.style.background=''}>
                    <td style={{...cell,fontWeight:700,color:'#111827',fontSize:13}}>{c.cls}</td>
                    <td style={{...cell,textAlign:'center'}}>
                      <span style={{padding:'3px 10px',borderRadius:20,background:'#EDE9F8',color:'#1E1B4B',fontWeight:700}}>{c.total}</span>
