                    <td style={{...cell,textAlign:'center',fontWeight:700,color:'#065F46'}}>{c.present}</td>
                    <td style={{...cell,textAlign:'center',fontWeight:700,color:'#991B1B'}}>{c.absent}</td>
                    <td style={{...cell,textAlign:'center',fontWeight:700,color:'#92400E'}}>{c.leave}</td>
                    <td style={{...cell,textAlign:'center',fontWeight:700,color:'#5B21B6'}}>{c.late}</td>
                    <td style={{...cell,textAlign:'center',color:'#9CA3AF'}}>{c.unmarked}</td>
                    <td style={{...cell,textAlign:'center'}}><Pct v={c.pct}/></td>
                    <td style={{...cell,minWidth:160}}>
                      <Bar pct={c.pct}/>
