              {classSummary.length>0&&(
                <tfoot>
                  <tr style={{background:'#F9FAFB',borderTop:'2px solid #E5E7EB'}}>
                    <td style={{...cell,fontWeight:800,color:'#111827'}}>GRAND TOTAL</td>
                    <td style={{...cell,textAlign:'center',fontWeight:800}}>{classSummary.reduce((a,c)=>a+c.total,0)}</td>
                    <td style={{...cell,textAlign:'center',fontWeight:800,color:'#065F46'}}>{classSummary.reduce((a,c)=>a+c.present,0)}</td>
