                    <td style={{...cell,textAlign:'center',fontWeight:800,color:'#92400E'}}>{classSummary.reduce((a,c)=>a+c.leave,0)}</td>
                    <td style={{...cell,textAlign:'center',fontWeight:800,color:'#5B21B6'}}>{classSummary.reduce((a,c)=>a+c.late,0)}</td>
