                      <td style={{...cell,color:isSunday?'#F59E0B':'#6B7280',fontWeight:isSunday?700:400}}>{dayName}</td>
                      <td style={{...cell,textAlign:'center',fontWeight:600,color:'#1E1B4B'}}>{r.total}</td>
                      <td style={{...cell,textAlign:'center',color:'#6B7280'}}>{r.marked}</td>
                      <td style={{...cell,textAlign:'center',fontWeight:700,color:'#065F46'}}>{r.present}</td>
                      <td style={{...cell,textAlign:'center',fontWeight:700,color:'#991B1B'}}>{r.absent}</td>
                      <td style={{...cell,textAlign:'center',color:'#D1D5DB'}}>{r.total-r.marked}</td>
                      <td style={{...cell,textAlign:'center'}}>
                        {isSunday&&!r.marked
                          ? <span style={{fontSize:10,color:'#F59E0B',fontWeight:600}}>Sunday</span>
                          : <Pct v={r.pct}/>}
                      </td>
                      <td style={{...cell,minWidth:120}}>
                        {r.pct!==null ? <Bar pct={r.pct}/> : <span style={{fontSize:10,color:'#D1D5DB'}}>Not marked</span>}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
              <tfoot>
                <tr style={{background:'#F9FAFB',borderTop:'2px solid #E5E7EB'}}>
                  <td colSpan={2} style={{...cell,fontWeight:800,color:'#111827'}}>MONTH TOTAL</td>
                  <td style={{...cell,textAlign:'center',fontWeight:800,color:'#1E1B4B'}}>{students.length}</td>
                  <td style={{...cell,textAlign:'center',fontWeight:700,color:'#6B7280'}}>{monthlyData.reduce((a,r)=>a+r.marked,0)}</td>
                  <td style={{...cell,textAlign:'center',fontWeight:800,color:'#065F46'}}>{monthlyData.reduce((a,r)=>a+r.present,0)}</td>
                  <td style={{...cell,textAlign:'center',fontWeight:800,color:'#991B1B'}}>{monthlyData.reduce((a,r)=>a+r.absent,0)}</td>
                  <td style={{...cell,textAlign:'center',color:'#9CA3AF',fontWeight:700}}>{monthlyData.reduce((a,r)=>a+(r.total-r.marked),0)}</td>
                  <td style={{...cell,textAlign:'center'}}>
                    <Pct v={(()=>{const tot=monthlyData.reduce((a,r)=>a+r.marked,0);const pre=monthlyData.reduce((a,r)=>a+r.present,0);return tot>0?Math.round((pre/tot)*100):null;})()}/>
                  </td>
                  <td style={cell}/>
                </tr>
              </tfoot>
            </table>
          </div>
        </>
      )}
    </div>
  );
}
